import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"电汇入金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/hk-methods/wire-transfer.md","filePath":"zh-CN/deposit/hk-methods/wire-transfer.md"}'),i={name:"deposit/hk-methods/wire-transfer.md"};function o(l,t,h,n,s,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="电汇入金" tabindex="-1">电汇入金 <a class="header-anchor" href="#电汇入金" aria-label="Permalink to &quot;电汇入金&quot;">​</a></h1><p>电汇仅支持<strong>跨境银行卡</strong>（非香港银行卡）转账入金，通过手机银行或网上银行操作。</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>支持币种</td><td>港元（HKD）、美元（USD）</td></tr><tr><td>预计到账时间</td><td>预计 2–5 个交易日，取决于银行操作</td></tr><tr><td>手续费</td><td>长桥免费；国际电汇到工银亚洲收费 60 HKD（或等值外币）；中转银行可能额外收费</td></tr></tbody></table><h2 id="收款银行信息" tabindex="-1">收款银行信息 <a class="header-anchor" href="#收款银行信息" aria-label="Permalink to &quot;收款银行信息&quot;">​</a></h2><p>中国工商银行（亚洲）有限公司</p><table tabindex="0"><thead><tr><th>字段</th><th>内容</th></tr></thead><tbody><tr><td>收款人名称</td><td>Long Bridge HK Limited</td></tr><tr><td>港元收款账号</td><td>861520160012</td></tr><tr><td>美元收款账号</td><td>861530198867</td></tr><tr><td>银行编号</td><td>072</td></tr><tr><td>SWIFT 代码</td><td>UBHKHKHHXXX</td></tr><tr><td>银行地址</td><td>33/F, ICBC Tower, 3 Garden Road, Central, Hong Kong</td></tr></tbody></table><h2 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h2><ol><li>在长桥 App 查看收款银行账户信息（资产 → 存入资金 → 选择币种 → 电汇）</li><li>通过手机银行或网上银行，将资金从跨境银行卡转至长桥收款账户</li><li>完成汇款后保留汇款凭证截图</li><li>返回长桥 App，上传汇款凭证</li></ol><blockquote><p>完成转账后请立即上传凭证，否则影响入金进度。</p></blockquote><h2 id="支持的国家和地区" tabindex="-1">支持的国家和地区 <a class="header-anchor" href="#支持的国家和地区" aria-label="Permalink to &quot;支持的国家和地区&quot;">​</a></h2><p>仅支持 FATF 成员国家/地区的跨境银行转账。请勿使用非 FATF 成员国家/地区的银行卡转账，入金会被退回且退款手续费由客户自行承担。</p><h2 id="账户要求与大陆银行卡限制" tabindex="-1">账户要求与大陆银行卡限制 <a class="header-anchor" href="#账户要求与大陆银行卡限制" aria-label="Permalink to &quot;账户要求与大陆银行卡限制&quot;">​</a></h2><ul><li>暂不接受中国大陆银行发行的银行卡转账，款项将退回，产生的手续费不退还</li><li>转账银行账户名必须与证券账户名同名，不可使用他人账户转账</li><li>香港公众假期不处理汇款业务，请预留时间</li><li>不接受直接存入现金</li></ul><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/deposit/methods-overview">入金方式总览</a> — 对比所有入金方式的预计到账时间与手续费</li><li><a href="/wiki/troubleshooting/deposit-not-received">入金未到账排查</a> — 超出预期时间未到账时的排查步骤</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/deposit">入金</a></li></ul>',18)])])}const b=a(i,[["render",o]]);export{p as __pageData,b as default};
